module RefModule(
    input [4:0] A,
    input [4:0] B,
    output [5:0] Sum
);
    wire [4:0] obf_P; // Propagate
    wire [4:0] G; // Generate
    wire [4:0] C; // Carry

    // Generate and propagate signals
    assign obf_P = A ^ B; // Propagate
    assign G = A & B; // Generate

    // Carry generation using Brent-Kung logic
    assign C[0] = G[0];
    assign C[1] = G[1] | (obf_P[1] & G[0]);
    assign C[2] = G[2] | (obf_P[2] & G[1]) | (obf_P[2] & obf_P[1] & G[0]);
    assign C[3] = G[3] | (obf_P[3] & G[2]) | (obf_P[3] & obf_P[2] & G[1]) | (obf_P[3] & obf_P[2] & obf_P[1] & G[0]);
    assign C[4] = G[4] | (obf_P[4] & G[3]) | (obf_P[4] & obf_P[3] & G[2]) | (obf_P[4] & obf_P[3] & obf_P[2] & G[1]) | (obf_P[4] & obf_P[3] & obf_P[2] & obf_P[1] & G[0]);

    // Sum calculation
    assign Sum = {C[4], obf_P} ^ {C[3:0], 1'b0};

endmodule
